mapper.select:
/* DisplayCategoryQueryMyBatisDao.getCategoryTreeList */ SELECT PDCB.DISP_CTG_NO , PDCBM.DISP_CTG_NM , PDCB.DISP_SEQ , PDCB.UPR_DISP_CTG_NO , PDCB.LRG_CTG_NO , PDCB.MID_CTG_NO , PDCB.SML_CTG_NO , PDCB.THN_CTG_NO , PDCB.SITE_NO , PDCB.DPML_NO , PDCB.LEAF_YN , CASE WHEN PDCB.LEAF_YN = 'Y' THEN CAST ((SELECT COUNT(1) FROM PR_DISP_GOODS_INFO PDGI WHERE PDGI.DISP_CTG_NO = PDCB.DISP_CTG_NO) AS TEXT) ELSE '' END AS CAT_GOODS_CNT FROM PR_DISP_CTG_BASE PDCB INNER JOIN PR_DISP_CTG_BASE_ML PDCBM ON PDCB.DISP_CTG_NO = PDCBM.DISP_CTG_NO AND PDCBM.LANG_CD = #{langCd} WHERE PDCB.SITE_NO = #{siteNo}
AND PDCB.USE_YN = #{useYn} AND NOT EXISTS ( SELECT 1 FROM PR_DISP_CTG_BASE UPPER_PDCB WHERE UPPER_PDCB.DISP_CTG_NO IN (PDCB.LRG_CTG_NO, PDCB.MID_CTG_NO, PDCB.SML_CTG_NO, PDCB.THN_CTG_NO) AND UPPER_PDCB.USE_YN <> 'Y' )
AND PDCB.DPML_NO = #{dpmlNo} ORDER BY PDCB.UPR_DISP_CTG_NO, PDCB.DISP_SEQ, PDCB.SYS_MOD_DTM DESC

/* DisplayCategoryQueryMyBatisDao.getSubCategoryListCount */
SELECT COUNT(1)
FROM PR_DISP_CTG_BASE PDCB
WHERE PDCB.UPR_DISP_CTG_NO = #{dispCtgNo}

/* DisplayCategoryQueryMyBatisDao.getDisplayGoodsListCount */
SELECT COUNT(1)
FROM PR_DISP_GOODS_INFO PDGI
WHERE PDGI.DISP_CTG_NO = #{dispCtgNo}

    AND PDGI.DISP_YN = #{dispYn}

/* DisplayCategoryQueryMyBatisDao.getDisplayGoodsList */ SELECT PDGI.DISP_CTG_NO , PDGI.GOODS_NO , PDGI.DISP_YN , PDGI.SYS_MOD_ID , PDGI.SYS_MOD_DTM , PGBM.GOODS_NM , FN_GET_CODENAME('PR002', PGB.GOODS_TYP_CD) AS GOODS_TYP_CD , PGPH.NOR_PRC , PGPH.SALE_PRC , FN_GET_CODENAME('PR005', PGB.SALE_STAT_CD) AS SALE_STAT_CD , EEB.ENTR_NM , PGB.GOODS_REG_DTM AS SYS_REG_DTM FROM PR_GOODS_BASE PGB INNER JOIN PR_DISP_GOODS_INFO PDGI ON PDGI.GOODS_NO = PGB.GOODS_NO INNER JOIN PR_GOODS_BASE_ML PGBM ON PGBM.GOODS_NO = PGB.GOODS_NO AND PGBM.LANG_CD = #{langCd} INNER JOIN PR_GOODS_PRCE_HIST PGPH ON PGB.GOODS_NO = PGPH.GOODS_NO AND NOW() BETWEEN PGPH.HIST_STR_DTM AND PGPH.HIST_END_DTM INNER JOIN ET_ENTR_BASE EEB ON PGB.ENTR_NO = EEB.ENTR_NO WHERE PDGI.DISP_CTG_NO = #{dispCtgNo}
AND PDGI.DISP_YN = #{dispYn}
AND PGB.SALE_STAT_CD = #{saleStatCd}
ORDER BY PGB.GOODS_REG_DTM DESC LIMIT #{rowsPerPage} OFFSET (#{pageIdx} - 1) * #{rowsPerPage}

/* DisplayCategoryQueryMyBatisDao.getGoodsListDetail */ SELECT PGB.GOODS_NO , PGBM.GOODS_NM , PGB.BRAND_NO , FN_GET_CODENAME('PR002', PGB.GOODS_TYP_CD) AS GOODS_TYP_CD , PGPH.NOR_PRC , PGPH.SALE_PRC , FN_GET_CODENAME('PR005', PGB.SALE_STAT_CD) AS SALE_STAT_CD , EEB.ENTR_NM , PGB.GOODS_REG_DTM AS SYS_REG_DTM FROM PR_GOODS_BASE PGB INNER JOIN PR_GOODS_BASE_ML PGBM ON PGB.GOODS_NO = PGBM.GOODS_NO AND PGBM.LANG_CD = #{langCd} INNER JOIN PR_GOODS_PRCE_HIST PGPH ON PGB.GOODS_NO = PGPH.GOODS_NO AND NOW() BETWEEN PGPH.HIST_STR_DTM AND PGPH.HIST_END_DTM INNER JOIN ET_ENTR_BASE EEB ON PGB.ENTR_NO = EEB.ENTR_NO WHERE PGB.GOODS_NO IN
#{item}
AND PGB.GOODS_NO NOT IN ( SELECT PDGI.GOODS_NO FROM PR_DISP_GOODS_INFO PDGI WHERE PDGI.DISP_CTG_NO = #{dispCtgNo} AND PDGI.GOODS_NO IN
#{item}
)

/* DisplayCategoryQueryMyBatisDao.getCheckPrDispGoodsInfo */
SELECT GOODS_NO
FROM PR_DISP_GOODS_INFO
WHERE DISP_CTG_NO = #{dispCtgNo}

/* DisplayCategoryQueryMyBatisDao.getMallList */
SELECT DPML_NO as "dpmlNo", DPML_NM as "dpmlNm"
FROM PR_DPML_BASE
WHERE SITE_NO = #{siteNo}
AND DISP_YN = 'Y'
ORDER BY DPML_NO
